import { useState } from 'react';

function TabContainer({ tabs, defaultTab = 0 }) {
  const [activeTab, setActiveTab] = useState(defaultTab);

  return (
    &lt;div className="tab-container"&gt;
      &lt;div className="tab-headers"&gt;
        {tabs.map((tab, index) => (
          &lt;button
            key={index}
            className={`tab-btn ${activeTab === index ? 'active' : ''}`}
            onClick={() => setActiveTab(index)}
          &gt;
            {tab.label}
          &lt;/button&gt;
        ))}
      &lt;/div&gt;
      &lt;div className="tab-content"&gt;
        {tabs[activeTab].content}
      &lt;/div&gt;
    &lt;/div&gt;
  );
}

// Exemple d'utilisation :
&lt;TabContainer
  tabs={[
    { label: 'Programme', content: &lt;ProgrammeComponent /&gt; },
    { label: 'Artistes', content: &lt;ArtistesList /&gt; },
    { label: 'Tarifs', content: &lt;TarifsComponent /&gt; }
  ]}
  defaultTab={1}
/&gt;
```

**Explication** : Le composant utilise `useState` pour gérer l'onglet actif. Il itère sur le tableau `tabs` pour générer les boutons d'onglet et affiche le contenu correspondant à l'onglet sélectionné. La prop `defaultTab` permet de définir l'onglet ouvert par défaut. Ce composant est générique car il fonctionne avec n'importe quel contenu.

