// Version refactorisée utilisant la composition par props nommées
function Dashboard({ sidebar, mainContent }) {
  return (
    &lt;div className="dashboard"&gt;
      &lt;div className="sidebar"&gt;
        {sidebar}
      &lt;/div&gt;
      &lt;div className="main"&gt;
        {mainContent}
      &lt;/div&gt;
    &lt;/div&gt;
  );
}

// Version encore plus flexible avec children multiple
function Dashboard({ children }) {
  // On suppose que children est un tableau avec [sidebar, main]
  const [sidebar, main] = React.Children.toArray(children);
  return (
    &lt;div className="dashboard"&gt;
      &lt;div className="sidebar"&gt;{sidebar}&lt;/div&gt;
      &lt;div className="main"&gt;{main}&lt;/div&gt;
    &lt;/div&gt;
  );
}

// Composant pour la zone principale flexible
function MainSection({ stats, chart, notifications }) {
  return (
    &lt;&gt;
      &lt;div className="stats"&gt;{stats}&lt;/div&gt;
      &lt;div className="chart"&gt;{chart}&lt;/div&gt;
      &lt;div className="notifications"&gt;{notifications}&lt;/div&gt;
    &lt;/&gt;
  );
}

// Utilisation refactorisée
&lt;Dashboard
  sidebar={&lt;UserProfile user={profileData} /&gt;}
  mainContent={
    &lt;MainSection
      stats={&lt;UserStats data={statsData} /&gt;}
      chart={&lt;ActivityChart data={chartData} /&gt;}
      notifications={&lt;NotificationsList items={notifsData} /&gt;}
    /&gt;
  }
/&gt;

// Ou encore mieux, en utilisant children :
&lt;Dashboard&gt;
  &lt;UserProfile user={profileData} /&gt;
  &lt;MainSection&gt;
    &lt;UserStats data={statsData} /&gt;
    &lt;ActivityChart data={chartData} /&gt;
    &lt;NotificationsList items={notifsData} /&gt;
  &lt;/MainSection&gt;
&lt;/Dashboard&gt;
```

**Explication** : Cette refactorisation applique le principe de séparation des préoccupations. Dashboard ne connaît que la mise en page. MainSection s'occupe de l'agencement des trois zones. Chaque composant spécifique est passé comme children ou props, permettant une flexibilité totale.

