function PageLayout({
  header,
  sidebar = null,
  sidebarPosition = 'left', // 'left' ou 'right'
  children, // contenu principal
  footer,
  extraSlots = {} // pour des zones additionnelles
}) {
  const hasSidebar = sidebar !== null;

  return (
    &lt;div className="page-layout"&gt;
      {header && &lt;header className="page-header"&gt;{header}&lt;/header&gt;}

      &lt;div className={`main-container ${hasSidebar ? `with-sidebar sidebar-${sidebarPosition}` : ''}`}&gt;
        {hasSidebar && sidebarPosition === 'left' && (
          &lt;aside className="sidebar left-sidebar"&gt;{sidebar}&lt;/aside&gt;
        )}

        &lt;main className="main-content"&gt;
          {children}
        &lt;/main&gt;

        {hasSidebar && sidebarPosition === 'right' && (
          &lt;aside className="sidebar right-sidebar"&gt;{sidebar}&lt;/aside&gt;
        )}
      &lt;/div&gt;

      {footer && &lt;footer className="page-footer"&gt;{footer}&lt;/footer&gt;}

      {/* Zones supplémentaires dynamiques */}
      {Object.entries(extraSlots).map(([slotName, slotContent]) => (
        &lt;div key={slotName} className={`slot-${slotName}`}&gt;
          {slotContent}
        &lt;/div&gt;
      ))}
    &lt;/div&gt;
  );
}

// Exemple d'utilisation complexe
&lt;PageLayout
  header={
    &lt;nav&gt;
      &lt;Logo /&gt;
      &lt;Menu /&gt;
      &lt;UserMenu /&gt;
    &lt;/nav&gt;
  }
  sidebar={
    &lt;&gt;
      &lt;UserProfile /&gt;
      &lt;NavigationMenu /&gt;
    &lt;/&gt;
  }
  sidebarPosition="left"
  footer={
    &lt;div className="footer-links"&gt;
      &lt;a href="/about"&gt;À propos&lt;/a&gt;
      &lt;a href="/contact"&gt;Contact&lt;/a&gt;
    &lt;/div&gt;
  }
  extraSlots={{
    'floating-chat': &lt;ChatWidget /&gt;,
    'cookie-banner': &lt;CookieConsent /&gt;
  }}
&gt;
  &lt;DashboardContent /&gt;
&lt;/PageLayout&gt;
```

**Explication** : Ce composant `PageLayout` est un excellent exemple de composition avancée. Il utilise des props nommées pour les différentes sections (header, sidebar, footer, extraSlots) et offre une flexibilité maximale. Le système `extraSlots` permet d'ajouter des zones supplémentaires sans modifier le composant. Ce pattern est utilisé dans des bibliothèques comme react-router (avec Outlet) ou des frameworks comme Next.js.
